CREATE TABLE sys_rules (
    id INTEGER NOT NULL,
    model_id INTEGER,
    name VARCHAR NOT NULL,
    read boolean default false,
    write boolean default false,
    creation boolean default false,
    domain VARCHAR NOT NULL,
    domain_force VARCHAR NOT NULL,
    CONSTRAINT app_sys_rules_p_key PRIMARY KEY (id)
);

